Here are the public test cases for feature4_cookies:
{
  "description": "Setting one cookie emits a Set-Cookie header with the encoded name, value, and default path.",
  "cases": [
    {
      "input": {
        "feature": "cookies",
        "method": "get",
        "path": "/single"
      },
      "expected_output": "status=200\nbase64=false\nheaders={\"content-type\":[\"application/json\"],\"set-cookie\":[\"test=value; Path=/\"]}\nbody={}\n"
    },
    {
      "input": {
        "feature": "cookies",
        "method": "get",
        "path": "/multiple"
      },
      "expected_output": "status=200\nbase64=false\nheaders={\"content-type\":[\"application/json\"],\"set-cookie\":[\"test=value; Path=/\",\"test2=value2; Path=/\"]}\nbody={}\n"
    },
    {
      "input": {
        "feature": "cookies",
        "method": "get",
        "path": "/encoded"
      },
      "expected_output": "status=200\nbase64=false\nheaders={\"content-type\":[\"application/json\"],\"set-cookie\":[\"test=http%3A%2F%2F%20%5B%5D%20foo%3Bbar; Path=/\"]}\nbody={}\n"
    },
    {
      "input": {
        "feature": "cookies",
        "method": "get",
        "path": "/object"
      },
      "expected_output": "status=200\nbase64=false\nheaders={\"content-type\":[\"application/json\"],\"set-cookie\":[\"test=%7B%22foo%22%3A%22bar%22%7D; Path=/\"]}\nbody={}\n"
    },
    {
      "input": {
        "feature": "cookies",
        "method": "get",
        "path": "/domain"
      },
      "expected_output": "status=200\nbase64=false\nheaders={\"content-type\":[\"application/json\"],\"set-cookie\":[\"test=value; Domain=test.com; Expires=Tue, 01 Jan 2019 00:00:00 GMT; Path=/\"]}\nbody={}\n"
    }
  ]
}

Here are the public test cases for feature5_middleware:
{
  "description": "Global middleware runs before matching route handlers and can attach values used by the handler response.",
  "cases": [
    {
      "input": {
        "feature": "middleware",
        "variant": "global",
        "method": "get",
        "path": "/test"
      },
      "expected_output": "status=200\nbase64=false\nheaders={\"content-type\":[\"application/json\"]}\nbody={\"method\":\"get\",\"testMiddleware\":\"123\",\"testMiddleware2\":\"456\"}\n"
    },
    {
      "input": {
        "feature": "middleware",
        "variant": "global",
        "method": "post",
        "path": "/test/abc",
        "query": {
          "test": "queryValue"
        },
        "body": {
          "test": "bodyValue"
        }
      },
      "expected_output": "status=200\nbase64=false\nheaders={\"content-type\":[\"application/json\"]}\nbody={\"method\":\"get\",\"testMiddleware3\":\"abc\",\"testMiddleware4\":\"queryValue\",\"testMiddleware5\":\"bodyValue\"}\n"
    },
    {
      "input": {
        "feature": "middleware",
        "variant": "path",
        "method": "get",
        "path": "/test"
      },
      "expected_output": "status=200\nbase64=false\nheaders={\"content-type\":[\"application/json\"]}\nbody={\"middleware\":true,\"middlewareWildcard\":false,\"middlewareParam\":false}\n"
    }
  ]
}

